Future<void> main() async {
  testWidgets(
    'Take snapshots for iPhone',
    (tester) async {
      TestWidgetsFlutterBinding.ensureInitialized();

      await _runScreenshotTest(
        tester,
        device: SnapshotDevice.iPhone15,
      );

      await _runScreenshotTest(
        tester,
        device: SnapshotDevice.iPhone15,
        locale: const Locale('ja'),
        isDarkMode: true,
      );
    },
    tags: ['vrt'],
  );

  // testWidgets(
  //   'Take snapshots for Android',
  //   (tester) async {
  //     TestWidgetsFlutterBinding.ensureInitialized();
  //
