@GenerateScenario()
Widget sessionDetailsPageWithData(BuildContext context) {
  const teamId = 'teamId';
  const sessionId = 'sessionId';
  final session = Session(
    id: sessionId,
    userId: 'userId',
    teamId: 'teamId',
    playerId: 'playerId',
    title: 'VRT Session',
    location: 'Ballpark',
    note: 'VRT note',
    createdAt: _kVrtNow,
    updatedAt: _kVrtNow,
  );

  // Mock ResourceData
  final pitchTypes = _mockPitchTypes().right;
  final fb = pitchTypes.firstWhere((p) => p.pitchType == '4_seam_fastball');

  final pitchBall = Ball(
    id: 1,
    isPitched: true,
    pitchType: fb,
    pitchTypeId: fb.id,
    activeSpin: 583.733154296875,
    efficiency: 0.40081229595058165,
    gyroDegree: 66.37103115455103,
    horizontalBreak: -0.11350476741790771,
    initialVelocity: 105.19886016845703,
    spinDirection: 0.8202007827201956,
    totalSpin: 1456.3753662109375,
    verticalBreak: 0.05358629301190376,
  );
  final hitBall = Ball(
    id: 21499,
    ballIndex: 1,
    isHit: true,
    isPitched: false,
    exitVelocity: 94.15625044450394,
    angle: 1.5438827636656247,
  );
  final multiPitch1 = pitchBall;
  final multiPitch2 = pitchBall;

  final resources = <ResourceData>[
    // 解析成功（投球）
    ResourceData(
      id: 'r_pitch',
      status: 3000,
      createdAt: _kVrtNow.subtract(const Duration(minutes: 12)),
      ballInfoList: [BallInfo(ball: pitchBall, positions: null)],
      teamId: teamId,
      sessionId: sessionId,
    ),
    // 解析成功（打撃）
    ResourceData(
      id: 'r_hit',
      status: 3000,
      createdAt: _kVrtNow.subtract(const Duration(minutes: 11)),
      ballInfoList: [BallInfo(ball: hitBall, positions: null)],
      teamId: teamId,
      sessionId: sessionId,
    ),
    // 解析成功（複数投球）
    ResourceData(
      id: 'r_multi',
      status: 3000,
      createdAt: _kVrtNow.subtract(const Duration(minutes: 10)),
      ballInfoList: [
        BallInfo(ball: multiPitch1, positions: null),
        BallInfo(ball: multiPitch2, positions: null),
      ],
      teamId: teamId,
      sessionId: sessionId,
    ),
    // キュー待ち
    ResourceData(
      id: 'r_queue',
      status: 0,
      createdAt: _kVrtNow.subtract(const Duration(minutes: 9)),
      ballInfoList: null,
      teamId: teamId,
      sessionId: sessionId,
    ),
    // 解析中
    ResourceData(
      id: 'r_in_analysis',
      status: 2000,
      createdAt: _kVrtNow.subtract(const Duration(minutes: 8)),
      ballInfoList: null,
      teamId: teamId,
      sessionId: sessionId,
    ),
    // 解析失敗
    ResourceData(
      id: 'r_failed',
      status: 4000,
      createdAt: _kVrtNow.subtract(const Duration(minutes: 7)),
      ballInfoList: null,
      teamId: teamId,
      sessionId: sessionId,
    ),
    // ローカルのみ
    ResourceData(
      id: 'r_local',
      status: -1,
      createdAt: _kVrtNow.subtract(const Duration(minutes: 6)),
      ballInfoList: null,
      teamId: teamId,
      sessionId: sessionId,
    ),
  ];

  final paging = PagingData<ResourceData>(
    items: resources,
    page: 0,
    pageSize: 20,
    total: resources.length,
    hasMore: false,
  );

  // Provider overrides
  final overrides = <Override>[
    // リソース一覧
    resourceDataListControllerProvider(
      teamId: teamId,
      sessionId: sessionId,
    ).overrideWith(() => FakeResourceDataListController(data: paging)),

    // アクセス権
    userAccessibleContentsControllerProvider
        .overrideWith(() => FakeUserAccessibleContentsController()),

    // チーム一覧（録画可否判定で参照）
    teamListControllerProvider
        .overrideWith(() => FakeTeamListController(result: _mockTeams(teamId))),

    // 球種リスト（ドロップダウン用）
    pitchTypeListControllerProvider
        .overrideWith(() => FakePitchTypeListController(Right(pitchTypes))),

    // ユーザー情報（userId / teamId 等）
    profileStorageProvider.overrideWith(
        (ref) => FakeProfileStorage(userId: 'userId', teamId: teamId)),
  ];

  return ProviderScope(
    overrides: overrides,
    child: SessionDetailsPage(
      teamId: teamId,
      sessionId: sessionId,
      session: session,
    ),
  );
}

// ---------- mock helpers ----------

Result<Failure, List<Team>> _mockTeams(String teamId) {
  return Right([
    Team(
      id: teamId,
      name: 'Demo Team',
      teamType: TeamType.single,
      teamPlan: TeamPlan(
          id: 'plan',
