          currentUsage: 0,
          extraBalls: 0,
          plan: Plan(
            isPaid: false,
            isActive: true,
            maxBalls: 1000,
          )),
    )
  ]);
}

Result<Failure, List<PitchType>> _mockPitchTypes() {
  return Right([
    PitchType(
      id: '8421a700-bc03-487d-883f-2d43c182c78d',
      pitchType: '4_seam_fastball',
      priority: 10,
      groupingTag: 'fastball',
    ),
  ]);
}

