// Project imports:
import 'package:baseball_detector_flutter/controllers/resource_data_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/paging_data.dart';
import 'package:baseball_detector_flutter/data/models/resource.dart';

class FakeResourceDataListController extends ResourceDataListController {
  FakeResourceDataListController({this.data});

  final PagingData<ResourceData>? data;

  @override
  Future<PagingData<ResourceData>> build({
    required String teamId,
    required String sessionId,
  }) async {
    if (data != null) return data!;
    final item = ResourceData(
      id: 'res-1',
      teamId: teamId,
      sessionId: sessionId,
      status: 3000,
      userId: 'userId',
      recordedAt: DateTime.utc(2024, 6, 12, 3, 24, 33, 330),
    );
    final items = List.generate(6, (i) => item.copyWith(id: 'res-${i + 1}'));
    return PagingData(
      items: items,
      page: 0,
      pageSize: 20,
      total: items.length,
      hasMore: false,
    );
  }
}

