Future<void> _runScreenshotTest(
  WidgetTester tester, {
  required SnapshotDevice device,
  Locale locale = const Locale('en'),
  bool isDarkMode = false,
}) async {
  const storyTitle = String.fromEnvironment('STORY_TITLE');
  final story =
      stories.where((element) => element.title == storyTitle).toList();

  await Playbook(stories: story.isNotEmpty ? story : stories).run(
    Snapshot(
      devices: [device],
      checkeredRectSize: 4,
      subDir: locale.languageCode,
    ),
    tester,
    (widget, device) {
      return ProviderScope(
        overrides: [
          profileStorageProvider.overrideWithValue(
            FakeProfileStorage(isDarkMode: isDarkMode),
          ),
          teamListControllerProvider
              .overrideWith(() => FakeTeamListController()),
          darkModeProvider.overrideWith(
            () => FakeDarkMode(isDarkMode: isDarkMode),
          ),
          authClientProvider.overrideWithValue(FakeAuthClient()),
          repositoryProvider.overrideWithValue(FakeRepository()),
          userInfoControllerProvider
              .overrideWith(() => FakeUserInfoController()),
          appLinksProvider
              .overrideWithValue(FakeAppLinks(appLinks: AppLinks())),
          maintenanceControllerProvider.overrideWith(
            () => FakeMaintenanceController(),
          ),
          versionControllerProvider.overrideWith(
            () => FakeVersionController(),
          ),
          resourceDataListControllerProvider(
            teamId: 'teamId',
            sessionId: 'sessionId',
          ).overrideWith(
            () => FakeResourceDataListController(),
          ),
          playerListControllerProvider
              .overrideWith(() => FakePlayerListController()),
          resourceDataDetailControllerProvider(
            teamId: 'teamId',
            sessionId: 'sessionId',
            resourceId: 'pitching',
          ).overrideWith(
            () => FakeResourceDataDetailController(isPitching: true),
          ),
          resourceDataDetailControllerProvider(
            teamId: 'teamId',
            sessionId: 'sessionId',
            resourceId: 'hitting',
          ).overrideWith(
            () => FakeResourceDataDetailController(isPitching: false),
          ),
          pitchTypeListControllerProvider.overrideWith(
            () => FakePitchTypeListController(),
          ),
          memberListControllerProvider.overrideWith(
            () => FakeMemberListController(),
          ),
          localeControllerProvider.overrideWith(
            () => FakeLocaleController(locale: locale),
          ),
          userAccessibleContentsControllerProvider.overrideWith(
            () => FakeUserAccessibleContentsController(),
          ),
          subscriptionControllerProvider
              .overrideWith(() => FakeSubscriptionController()),
          subscriptionPlansControllerProvider.overrideWith(
            (ref) async => locale.isJapanese ? jaPlans : enPlans,
          ),
          appUnitProvider.overrideWith(
            () => FakeAppUnit(
              unit: locale.isJapanese ? UnitType.kmhCm : UnitType.mphInch,
            ),
          )
        ],
        child: MaterialApp(
          debugShowCheckedModeBanner: false,
          locale: locale,
          localizationsDelegates: L10n.localizationsDelegates,
          supportedLocales: L10n.supportedLocales,
          theme: AppTheme.light.data,
          darkTheme: AppTheme.dark.data,
          themeMode: isDarkMode ? ThemeMode.dark : ThemeMode.light,
          home: Builder(
            builder: (context) {
              // Playbook 側が MediaQuery の値を差し込むため、影響を受けないようにする
              // See also: https://github.com/playbook-ui/playbook-flutter/blob/playbook_snapshot-v1.0.0/packages/playbook_snapshot/lib/src/snapshot.dart#L91-L96
              return MediaQuery.removePadding(
                context: context,
                removeLeft: true,
                removeTop: true,
                removeRight: true,
                removeBottom: true,
                child: widget,
              );
            },
          ),
        ),
      );
    },
  );
}

